          # Add language (and official language) information about the origin entity, if available.
          if "origin" in pred_objs:
              for origin_obj in pred_objs["origin"]:
                  # origin_obj is already cleaned by _clean when building subject_pred_objs
                  if origin_obj in subject_pred_objs:
                      # language of the origin place
                      lang_objs = subject_pred_objs[origin_obj].get("language", [])
                      if lang_objs:
                          lang_phrase = _join_objs(lang_objs)
                          clauses.append(f"where {lang_phrase} is spoken")
                      # official language of the origin place
                      offlang_objs = subject_pred_objs[origin_obj].get("officialLanguage", [])
                      if offlang_objs:
                          off_phrase = _join_objs(offlang_objs)
                          clauses.append(f"where the official language is {off_phrase}")

          # Combine clauses into a single fluent sentence.
          if not clauses:
              body = ""
          elif len(clauses) == 1:
              body = clauses[0]
